using System;
using System.Collections.Generic;
using System.IO;
using System.Xml;

public class ConfigurationParser
{
    public Dictionary<string, string> ParseXmlConfig(string filePath)
    {
        var configSettings = new Dictionary<string, string>();

        try
        {
            XmlDocument xmlDoc = new XmlDocument();
            xmlDoc.Load(filePath);

            // Validate against the referenced DTD file if available
            if (xmlDoc.DocumentElement.Attributes["dtd"] != null && File.Exists(xmlDoc.DocumentElement.Attributes["dtd"].Value))
            {
                XmlReaderSettings settings = new XmlReaderSettings();
                settings.ValidationType = ValidationType.DTD;
                using (XmlReader reader = XmlReader.Create(filePath, settings))
                {
                    xmlDoc.Load(reader);
                }
            }

            foreach (XmlNode node in xmlDoc.DocumentElement.ChildNodes)
            {
                if (!string.IsNullOrEmpty(node.Attributes["name"]?.Value))
                {
                    configSettings.Add(node.Attributes["name"].Value, node.InnerText);
                }
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine("Error parsing configuration file: " + ex.Message);
        }

        return configSettings;
    }
}